import uuid
import redis
from functools import wraps

r = redis.Redis()

def idempotent_payment(func):
    @wraps(func)
    def wrapper(request):
        key = request.headers.get('X-Idempotency-Key')
        if not key:
            return {'error': 'Idempotency key required'}, 400

        # Check if already processed
        cached = r.get(f'idem:{key}')
        if cached:
            import json
            return json.loads(cached), 200

        # Distributed lock to prevent concurrent processing
        lock = r.set(f'lock:{key}', '1', nx=True, ex=30)
        if not lock:
            return {'error': 'Request in progress, retry'}, 409

        try:
            result = func(request)
            import json
            r.setex(f'idem:{key}', 86400, json.dumps(result))
            return result, 201
        finally:
            r.delete(f'lock:{key}')
    return wrapper

@idempotent_payment
def create_payment(request):
