import threading

class DatabaseConnectionPool:
    _instance = None
    _lock = threading.Lock()

    def __new__(cls):
        if cls._instance is None:
            with cls._lock:
                # Double-checked locking
                if cls._instance is None:
                    cls._instance = super().__new__(cls)
                    cls._instance._initialized = False
        return cls._instance

    def __init__(self):
        if self._initialized:
            return
        self.connections = []
        self.max_connections = 10
        self._initialized = True
        print('Connection pool initialized')

# Thread-safe test
def get_pool():
    pool = DatabaseConnectionPool()
    print(f'Pool id: {id(pool)}')

threads = [threading.Thread(target=get_pool) for _ in range(5)]
for t in threads:
    t.start()
for t in threads:
    t.join()
# All threads should print the same id

from collections import Counter

def two_sum_all_pairs(nums, target):
    count = Counter(nums)
    pairs = []
    seen = set()

    for num in nums:
        complement = target - num
        pair = (min(num, complement), max(num, complement))
        if complement in count and pair not in seen:
            if num == complement and count[num] < 2:
                continue
            pairs.append(pair)
            seen.add(pair)
    return pairs

print(two_sum_all_pairs([1, 5, 3, 3, 2, 4, 1], 6))
# [(1, 5), (3, 3), (2, 4)]

# Two pointer version (requires sorted)
def two_sum_sorted(nums, target):
    nums.sort()
    left, right = 0, len(nums) - 1
    pairs = []
    while left < right:
        s = nums[left] + nums[right]
        if s == target:
            pairs.append((nums[left], nums[right]))
            while left < right and nums[left] == nums[left+1]:
                left += 1
            while left < right and nums[right] == nums[right-1]:
                right -= 1
            left += 1
            right -= 1
        elif s < target:
            left += 1
        else:
            right -= 1
    return pairs

def is_valid(s):
    stack = []
    matching = {')': '(', '}': '{', ']': '['}

    for char in s:
        if char in '({[':
            stack.append(char)
        elif char in ')}]':
            if not stack or stack[-1] != matching[char]:
                return False
            stack.pop()

    return len(stack) == 0

print(is_valid('()[]{}'))   # True
print(is_valid('([)]'))     # False
print(is_valid('{[]}'))     # True
print(is_valid('('))        # False
